<template>
  <div class="publication animate__animated animate__zoomIn">
    <div class="publication-wrap">
      <div class="publication-card" v-for="(card, index) in cards" :key="index">
        <div class="front">
          <img :src="card.imageUrl" :fit="'fill'" width="100%" />
          <div class="publication-date">
            <i>{{ card.date }}</i>
          </div>
        </div>
        <div class="back">
          <div class="publication-title">
            <div class="publication-type">
              <b>{{ card.type }}</b>:&nbsp;
              <a :href="card.publicationUrl" target="_blank" class="a-decoration"><i class="publication-text">{{
        card.publication }}</i></a>
            </div>
            <div class="publication-if">
              <i>IF&nbsp;{{ card.ifactor }}&nbsp;&nbsp;CCF&nbsp;{{
        card.ccf
      }}</i>
            </div>
          </div>
          <div class="publication-name">{{ card.name }}</div>
          <div class="publication-authors">
            <b v-if="card.firstAuthor == 'Benyu Wu'">{{ card.firstAuthor }} </b>
            <span v-else>{{ card.firstAuthor }}</span>,
            <b v-if="card.secondAuthor == 'Benyu Wu'">{{
        card.secondAuthor
      }}</b>
            <span v-else>{{ card.secondAuthor }}</span>,
            <div>{{ card.otherAuthors }},</div>
            <div>{{ card.correspondingAuthor }}*</div>
          </div>
          <div class="timeline">
            <el-timeline>
              <el-timeline-item icon="el-icon-check" type="success" :size="'large'" :timestamp="card.acceptDate">
                Accepted
              </el-timeline-item>
              <el-timeline-item icon="el-icon-edit" type="warning" :size="'large'" :timestamp="card.reviseDate">
                Finally Revised
              </el-timeline-item>
              <el-timeline-item icon="el-icon-check" type="primary" :size="'large'" :timestamp="card.receiveDate">
                Received
              </el-timeline-item>
            </el-timeline>
          </div>
          <div class="links">
            <div class="publication-sourceCode">
              <div style="margin-bottom: 2vh">
                <span style="font-size: 1vw; color: #fe510d"><el-icon
                    class="el-icon-document"></el-icon>&nbsp;&nbsp;&nbsp;<a :href="card.doi" target="_blank"
                    class="a-decoration">Paper</a></span>
              </div>
              <div style="margin-top: 2vh">
                <span style="font-size: 1vw; color: #fe510d">&lt;/&gt;&nbsp;&nbsp;<a :href="card.sourceCode"
                    target="_blank" class="a-decoration">Code</a></span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: "Publication",
  data() {
    return {
      cards: [
        {
          imageUrl: require("@/assets/gcsee.jpg"),
          name: "Graph Clustering Network with Strcuture Embedding Enhanced",
          date: "2023/07/21",
          receiveDate: "28 February 2023",
          reviseDate: "11 July 2023",
          acceptDate: "21 July 2023",
          type: "Journal",
          publication: "Pattern Recognition",
          publicationUrl:
            "https://www.sciencedirect.com/journal/pattern-recognition",
          ccf: "B",
          ifactor: "8.0",
          firstAuthor: "Shifei Ding",
          secondAuthor: "Benyu Wu",
          otherAuthors: "Xiao Xu, Lili Guo",
          correspondingAuthor: "Ling Ding",
          abstract:
            "Recently, deep clustering utilizing Graph Neural Networks has shown good performance in the graph clustering. However, the structure information of graph was underused in existing deep clustering methods. Particularly, the lack of concern on mining different types structure information simultaneously. To tackle with the problem, this paper proposes a Graph Clustering Network with Structure Embedding Enhanced (GC-SEE) which extracts nodes importance-based and attributes importance-based structure information via a feature attention fusion graph convolution module and a graph attention encoder module respectively. Additionally, it captures different orders-based structure information through multi-scale feature fusion. Finally, a self-supervised learning module has been designed to integrate different types structure information and guide the updates of the GC-SEE. The comprehensive experiments on benchmark datasets commonly used demonstrate the superiority of the GC-SEE. The results showcase the effectiveness of the GC-SEE in exploiting multiple types of structure for deep clustering.",
          bibTex: "",
          doi: "https://doi.org/10.1016/j.patcog.2023.109833",
          paperUrl:
            "https://www.sciencedirect.com/science/article/pii/S0031320323005319",
          sourceCode: "https://github.com/Marigoldwu/GC-SEE",
        },
      ],
    };
  },
  methods: {},
};
</script>

